        { "name": "nombre", "label": "Nombre completo", "type": "text", "required": true },
        { "name": "email", "label": "Correo electrónico", "type": "email", "required": true },
        { "name": "telefono", "label": "Teléfono", "type": "tel", "required": true },
        { "name": "servicio", "label": "Servicio de interés", "type": "select", "options": ["Escrituras", "Poderes", "Contratos", "Legalizaciones", "Sucesiones", "Societario", "Otro"], "required": false },
        { "name": "mensaje", "label": "Mensaje", "type": "textarea", "required": true }
      ],
      "submitText": "Enviar Consulta"
    },
    "cta": {
      "title": "¿Preferís una respuesta inmediata?",
      "subtitle": "Escribinos por WhatsApp y te respondemos al instante",
      "buttonText": "Escribir por WhatsApp",
      "buttonHref": "https://wa.me/{{whatsapp}}?text={{whatsappMessage}}"
    }
  },
  "faqPage": {
    "seo": {
      "title": "Preguntas Frecuentes | {{businessName}}",
      "description": "Respuestas a las preguntas más comunes sobre servicios notariales en Paraguay."
    },
    "hero": {
      "headline": "Preguntas Frecuentes",
      "subheadline": "Respondemos tus dudas sobre trámites notariales"
    },
    "categories": [
      {
        "title": "Trámites Generales",
        "items": [
          {
            "q": "¿Qué documentos necesito para identificarme ante el escribano?",
            "a": "Necesitás tu cédula de identidad civil vigente (paraguaya) o pasaporte vigente (extranjeros). Para actos que requieran capacidad especial, pueden solicitarse documentos adicionales."
          },
          {
            "q": "¿Cuánto cuesta una consulta inicial?",
            "a": "La consulta inicial es sin costo. Te asesoramos sobre la documentación, el proceso y los costos del servicio notarial que necesitás."
          },
          {
            "q": "¿Puedo firmar un documento si estoy en el extranjero?",
            "a": "Sí. Podés firmar ante un notario en tu país de residencia, apostillar/legalizar el documento y enviarlo a Paraguay. También podemos coordinar videoconferencia para ciertos actos."
          }
        ]
      },
      {
        "title": "Inmuebles y Propiedades",
        "items": [
          {
            "q": "¿Qué impuestos debo pagar al comprar un inmueble?",
            "a": "El comprador paga el Impuesto a la Transferencia de Inmuebles (ITI) del 4% sobre el valor fiscal actualizado. También hay gastos de registro y honorarios notariales. Te damos el presupuesto completo antes de iniciar."
          },
          {
            "q": "¿Es obligatorio firmar escritura pública para comprar un inmueble?",
            "a": "Sí, según el Código Civil paraguayo, la transferencia de dominio de inmuebles debe hacerse por escritura pública. Es la única forma de inscribir la propiedad a tu nombre en la Dirección General de Registros Públicos."
          }
        ]
      },
      {
        "title": "Empresas y Sociedades",
        "items": [
          {
            "q": "¿Qué tipo de sociedad me conviene?",
            "a": "Depende de tu actividad, capital y cantidad de socios. La SRL es ideal para PYMES, la SA para empresas grandes, y la EAS para pequeños emprendedores. Te asesoramos sin costo."
          },
          {
            "q": "¿Cuánto tiempo toma constituir una sociedad?",
            "a": "Aproximadamente 2 a 4 semanas, incluyendo la escritura pública, inscripción en la DGRRCC y obtención del RUC. Podemos hacer el proceso en paralelo para agilizar."
          }
        ]
      }
    ]
  },
  "privacidadPage": {
    "seo": {
      "title": "Política de Privacidad | {{businessName}}",
      "description": "Política de privacidad y tratamiento de datos personales de {{businessName}}."
    },
    "hero": {
      "headline": "Política de Privacidad",
      "subheadline": "Cómo protegemos tus datos personales"
    },
    "content": {
      "sections": [
        {
          "title": "1. Información que recopilamos",
          "text": "Recopilamos información personal que nos proporcionás voluntariamente al contactarnos, como nombre, correo electrónico, número de teléfono y datos de identificación necesarios para los servicios notariales."
        },
        {
          "title": "2. Uso de la información",
          "text": "Usamos tu información exclusivamente para: brindar los servicios notariales solicitados, comunicarnos con vos sobre tu trámite, cumplir con obligaciones legales y regulatorias, y mejorar nuestros servicios."
        },
        {
          "title": "3. Protección de datos",
          "text": "Implementamos medidas de seguridad técnicas y organizativas para proteger tus datos personales contra acceso no autorizado, pérdida o destrucción."
        },
        {
          "title": "4. Confidencialidad notarial",
          "text": "Como escribanos, estamos sujetos al secreto profesional y a la confidencialidad notarial. La información que compartís con nosotros está protegida por ley."
        },
        {
          "title": "5. Tus derechos",
          "text": "Tenés derecho a acceder, rectificar, cancelar y oponerte al tratamiento de tus datos personales. Contactanos para ejercer estos derechos."
        }
      ]
    }
  }
}
