{"action": "write_file", "name": "professional-services-website", "file_path": "templates/globals.css", "file_content": "@import "tailwindcss";

@theme {
  /* Professional Services — EDIT per client */
  --color-primary: #1a1a2e;
  --color-secondary: #2c2c54;
  --color-accent: #c9a96e;
  --color-accent-light: #e8d5a3;
  --color-background: #faf9f6;
  --color-foreground: #1a1a2e;
  --color-surface: #ffffff;
  --color-surface-alt: #f5f3ee;
  --color-muted: #6b7280;
  --color-border: #e5e2db;
  --color-success: #059669;
  --color-whatsapp: #25D366;
  --font-body: "Lora", Georgia, serif;
  --font-heading: "Playfair Display", Georgia, serif;
  --font-accent: "Inter", system-ui, sans-serif;
}

@layer base {
  html { scroll-behavior: smooth; }
  body {
    background-color: var(--color-background);
    color: var(--color-foreground);
    font-family: var(--font-body);
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }
  h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-heading);
    font-weight: 600;
  }
}

@layer components {
  .container-page { max-width: 1200px; margin: 0 auto; padding: 0 1.5rem; }
  .section-padding { padding: 5rem 0; }
  .section-padding-sm { padding: 3rem 0; }
  .gradient-accent { background: linear-gradient(135deg, var(--color-accent), var(--color-accent-light)); }
}
"}
